const input = $json || {};

const csvColumns = [
  'Nachname',
  'Vorname',
  'Straße',
  'Ort',
  'Status',
  'Zahlungsart',
  'Eintrittsdatum',
  'PLZ',
  'Geburtsdatum',
  'Geschlecht',
  'Mitglieds-Nr',
  'Anrede',
  'Land',
  'Telefon_P1',
  'Mobil_P1',
  'E-Mail_P1',
  'Titel',
  'Kontoinhaber',
  'IBAN',
  'BIC',
  'Kreditinstitut',
  'SEPA-Mandatstyp_1',
  'SEPA-Unterschriftsdatum_1',
  'SEPA-Merkmal_1',
  'SEPA-Gültigkeitsdatum_1',
  'SEPA-Benachrichtigungsdatum_1',
  'Abteilung_1',
  'Abteilungseintritt_1',
  'Abteilung_2',
  'Abteilungseintritt_2',
  'Abteilung_3',
  'Abteilungseintritt_3',
  'Abteilung_4',
  'Abteilungseintritt_4',
  'Abteilung_5',
  'Abteilungseintritt_5',
  'Abteilung_6',
  'Abteilungseintritt_6',
  'Abteilung_7',
  'Abteilungseintritt_7',
  'Abteilung_8',
  'Abteilungseintritt_8',
  'Abteilung_9',
  'Abteilungseintritt_9',
  'Beitragsbezeichnung_1_1',
  'Beitragsstart_1_1',
  'Beitragsende_1_1',
  'Beitragsbezeichnung_1_2',
  'Beitragsstart_1_2',
  'Beitragsende_1_2'
];

const allowedSports = new Set([
  'Fußball',
  'Volleyball',
  'Tischtennis',
  'Gymnastik',
  'Karate',
  'Radsport',
  'Walking'
]);

const sportAliases = {
  fussball: 'Fußball',
  fußball: 'Fußball',
  volleyball: 'Volleyball',
  tischtennis: 'Tischtennis',
  gymnastik: 'Gymnastik',
  karate: 'Karate',
  radsport: 'Radsport',
  walking: 'Walking'
};

const valueMap = {
  status: {
    aktiv: 'Aktiv',
    passiv: 'Passiv'
  },
  geschlecht: {
    maennlich: 'männlich',
    männlich: 'männlich',
    weiblich: 'weiblich',
    divers: 'divers',
    juristischeperson: 'jur. Person',
    jurperson: 'jur. Person',
    sachlich: 'sächlich'
  },
  zahlungsart: {
    lastschrift: 'Lastschrift',
    ueberweisung: 'Überweisung',
    überweisung: 'Überweisung',
    bar: 'Bar'
  },
  sepamandatstyp: {
    erstlastschrift: 'Erstlastschrift',
    folgelastschrift: 'Folgelastschrift'
  },
  sepamerkmal: {
    wiederkehrend: 'wiederkehrend',
    einmalig: 'einmalig'
  }
};

const contributionMap = {
  Aktiv: { half: 'Aktiv (halbjahr)' },
  Passiv: { half: 'Passiv (halbjahr)' },
  Jugendlich: { half: 'Jugendlich (halbjahr)' },
  Familie: { half: 'Familie (halbjahr)' },
  'Familie (nicht Zahlender)': { half: null },
  Beitragsfrei: { half: null }
};

const reverseHalfYearMap = {
  'Aktiv (halbjahr)': 'Aktiv',
  'Passiv (halbjahr)': 'Passiv',
  'Jugendlich (halbjahr)': 'Jugendlich',
  'Familie (halbjahr)': 'Familie'
};

function isObject(v) {
  return !!v && typeof v === 'object' && !Array.isArray(v);
}

function toLowerKey(k) {
  return String(k || '').trim().toLowerCase();
}

function normalizeKey(k) {
  return toLowerKey(k)
    .replace(/[ä]/g, 'ae')
    .replace(/[ö]/g, 'oe')
    .replace(/[ü]/g, 'ue')
    .replace(/[ß]/g, 'ss')
    .replace(/[^a-z0-9]+/g, '');
}

function parseKeyValueList(list) {
  const obj = {};
  for (const entry of list) {
    if (!isObject(entry)) continue;
    const rawKey = entry.key ?? entry.name ?? entry.field ?? entry.k;
    if (!rawKey) continue;
    const rawValue = entry.value ?? entry.v ?? '';
    obj[String(rawKey)] = rawValue;
  }
  return obj;
}

function splitSports(value) {
  if (Array.isArray(value)) return value;
  const text = String(value || '').trim();
  if (!text) return [];
  return text
    .split(/[|,;]+/)
    .map((v) => v.trim())
    .filter(Boolean);
}

function normalizeSport(s) {
  const key = normalizeKey(s);
  if (!key) return '';
  const mapped = sportAliases[key] || String(s).trim();
  return mapped;
}

function normalizeChoice(kind, value) {
  const raw = String(value ?? '').trim();
  if (!raw) return '';
  if (kind === 'zahlungsart') {
    if (/^lastschrift/i.test(raw)) return 'Lastschrift';
    if (/^ueberweisung/i.test(raw) || /^überweisung/i.test(raw)) return 'Überweisung';
    if (/^bar/i.test(raw)) return 'Bar';
  }
  const map = valueMap[kind] || {};
  const key = normalizeKey(raw);
  return map[key] || raw;
}

function parseDate(value) {
  const raw = String(value || '').trim();
  if (!raw) return null;
  const m = raw.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  if (!m) return null;
  const day = Number(m[1]);
  const month = Number(m[2]);
  const year = Number(m[3]);
  const d = new Date(Date.UTC(year, month - 1, day));
  if (d.getUTCFullYear() !== year || d.getUTCMonth() !== month - 1 || d.getUTCDate() !== day) return null;
  return { day, month, year, text: raw };
}

function formatDate(day, month, year) {
  const dd = String(day).padStart(2, '0');
  const mm = String(month).padStart(2, '0');
  return `${dd}.${mm}.${year}`;
}

function csvEscape(value) {
  const str = String(value ?? '');
  if (/[";\r\n]/.test(str)) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

function pickSourceItems(root) {
  if (Array.isArray(root?.members)) return root.members;
  if (Array.isArray(root?.records)) return root.records;
  if (Array.isArray(root?.items)) return root.items;
  if (Array.isArray(root?.data)) return root.data;
  if (Array.isArray(root)) return root;
  return [root];
}

function normalizeRecord(rawItem) {
  let source = rawItem;
  if (Array.isArray(source)) {
    source = parseKeyValueList(source);
  }

  if (!isObject(source)) {
    throw new Error('Jeder Datensatz muss ein Objekt oder eine key/value Liste sein.');
  }

  if (Array.isArray(source.keyValuePairs)) {
    source = { ...source, ...parseKeyValueList(source.keyValuePairs) };
  }

  const member = isObject(source.member) ? source.member : {};
  const bank = isObject(source.bank) ? source.bank : {};
  const communication = isObject(source.communication) ? source.communication : {};

  const normalizedByKey = {};
  for (const [k, v] of Object.entries(source)) {
    normalizedByKey[normalizeKey(k)] = v;
  }

  function get(...keys) {
    for (const key of keys) {
      const normalized = normalizeKey(key);
      if (normalizedByKey[normalized] !== undefined) return normalizedByKey[normalized];
    }
    return undefined;
  }

  const sportsRaw = get('sportart', 'sportarten', 'abteilung', 'abteilungen', 'sport')
    ?? source.sportart
    ?? source.sportarten
    ?? source.abteilungen
    ?? member.sportart
    ?? member.departments
    ?? [];

  const result = {
    Vorname: String(get('vorname', 'firstname', 'first_name') ?? member.firstName ?? source.firstName ?? '').trim(),
    Nachname: String(get('nachname', 'lastname', 'last_name') ?? member.lastName ?? source.lastName ?? '').trim(),
    Straße: String(get('strasse', 'straße', 'street') ?? member.street ?? source.street ?? '').trim(),
    PLZ: String(get('plz', 'zip', 'postalcode') ?? member.zip ?? source.zip ?? '').trim(),
    Ort: String(get('ort', 'city') ?? member.city ?? source.city ?? '').trim(),
    Geburtsdatum: String(get('geburtsdatum', 'birthdate') ?? member.birthDate ?? source.birthDate ?? '').trim(),
    Eintrittsdatum: String(get('eintrittsdatum', 'entrydate') ?? member.entryDate ?? source.entryDate ?? '').trim(),
    Geschlecht: normalizeChoice('geschlecht', get('geschlecht', 'gender') ?? member.gender ?? member.genderValue ?? source.gender ?? ''),
    Status: normalizeChoice('status', get('status') ?? source.status ?? ''),
    Beitragsart: String(get('beitragsart', 'beitrag', 'tarif', 'contributiontype') ?? source.beitragsart ?? source.contributionType ?? '').trim(),
    Sportarten: splitSports(sportsRaw).map(normalizeSport).filter(Boolean),
    Anrede: String(get('anrede', 'salutation') ?? member.salutation ?? source.salutation ?? '').trim(),
    Land: String(get('land', 'country') ?? member.country ?? member.countryValue ?? source.country ?? 'Deutschland').trim(),
    Telefon_P1: String(get('telefon', 'telefon_p1', 'phone') ?? communication.phone ?? source.phone ?? '').trim(),
    Mobil_P1: String(get('mobil', 'mobil_p1', 'mobile') ?? communication.mobile ?? source.mobile ?? '').trim(),
    'E-Mail_P1': String(get('e-mail', 'email', 'email_p1') ?? communication.email ?? source.email ?? '').trim(),
    Titel: String(get('titel', 'title') ?? member.title ?? source.title ?? '').trim(),
    'Mitglieds-Nr': String(get('mitglieds-nr', 'mitgliedsnummer', 'mitgliedsnr', 'membernumber') ?? source.memberNumber ?? '').trim(),
    Zahlungsart: normalizeChoice('zahlungsart', get('zahlungsart', 'paymentmethod') ?? source.zahlungsart ?? source.paymentMethod ?? ''),
    Kontoinhaber: String(get('kontoinhaber', 'accountholder') ?? bank.accountHolder ?? source.accountHolder ?? '').trim(),
    IBAN: String(get('iban') ?? bank.iban ?? source.iban ?? '').trim(),
    BIC: String(get('bic') ?? bank.bic ?? source.bic ?? '').trim(),
    Kreditinstitut: String(get('kreditinstitut', 'bankname') ?? bank.bankName ?? source.bankName ?? '').trim(),
    'SEPA-Mandatstyp_1': normalizeChoice('sepamandatstyp', get('sepa-mandatstyp_1', 'sepa_mandatstyp', 'sepamandatstyp') ?? source.sepaMandatstyp ?? 'Folgelastschrift'),
    'SEPA-Unterschriftsdatum_1': String(get('sepa-unterschriftsdatum_1', 'unterschriftsdatum') ?? source.unterschriftsdatum ?? '').trim(),
    'SEPA-Merkmal_1': normalizeChoice('sepamerkmal', get('sepa-merkmal_1', 'mandatsmerkmal') ?? source.mandatsmerkmal ?? 'wiederkehrend'),
    'SEPA-Gültigkeitsdatum_1': String(get('sepa-gueltigkeitsdatum_1', 'gültigkeitsdatum') ?? source.gueltigkeitsdatum ?? source.gültigkeitsdatum ?? '').trim(),
    'SEPA-Benachrichtigungsdatum_1': String(get('sepa-benachrichtigungsdatum_1', 'benachrichtigung') ?? source.benachrichtigung ?? '').trim()
  };

  if (!result.Zahlungsart) result.Zahlungsart = 'Lastschrift';

  return result;
}

function normalizeContributionType(inputValue) {
  const raw = String(inputValue || '').trim();
  if (!raw) return '';
  if (contributionMap[raw]) return raw;
  if (reverseHalfYearMap[raw]) return reverseHalfYearMap[raw];

  const normalizedRaw = normalizeKey(raw);
  for (const key of Object.keys(contributionMap)) {
    if (normalizeKey(key) === normalizedRaw) return key;
  }
  for (const [half, annual] of Object.entries(reverseHalfYearMap)) {
    if (normalizeKey(half) === normalizedRaw) return annual;
  }
  return raw;
}

function validateRecord(r, index) {
  const errors = [];
  const required = [
    'Vorname',
    'Nachname',
    'Straße',
    'PLZ',
    'Ort',
    'Geburtsdatum',
    'Eintrittsdatum',
    'Geschlecht',
    'Status',
    'Beitragsart'
  ];

  for (const field of required) {
    if (!String(r[field] || '').trim()) errors.push(`Pflichtfeld fehlt: ${field}`);
  }

  const sports = Array.from(new Set(r.Sportarten.map((s) => s.trim()).filter(Boolean)));
  if (sports.length === 0) errors.push('Mindestens eine zweite Sportart ist Pflicht.');

  const invalidSports = sports.filter((s) => !allowedSports.has(s));
  if (invalidSports.length) {
    errors.push(`Unbekannte Sportart(en): ${invalidSports.join(', ')}`);
  }

  const dBirth = parseDate(r.Geburtsdatum);
  const dEntry = parseDate(r.Eintrittsdatum);
  if (!dBirth) errors.push('Geburtsdatum muss im Format TT.MM.JJJJ vorliegen.');
  if (!dEntry) errors.push('Eintrittsdatum muss im Format TT.MM.JJJJ vorliegen.');

  if (!['Aktiv', 'Passiv'].includes(r.Status)) {
    errors.push(`Status ungueltig: ${r.Status}. Erlaubt: Aktiv, Passiv.`);
  }

  if (!['männlich', 'weiblich', 'divers', 'jur. Person', 'sächlich'].includes(r.Geschlecht)) {
    errors.push(`Geschlecht ungueltig: ${r.Geschlecht}.`);
  }

  r.Beitragsart = normalizeContributionType(r.Beitragsart);
  if (!contributionMap[r.Beitragsart]) {
    errors.push(`Beitragsart ungueltig: ${r.Beitragsart}.`);
  }

  if (errors.length) {
    throw new Error(`Datensatz ${index + 1}: ${errors.join(' | ')}`);
  }
}

function buildRow(record, index) {
  validateRecord(record, index);

  const row = {};
  for (const col of csvColumns) row[col] = '';

  row.Nachname = record.Nachname;
  row.Vorname = record.Vorname;
  row['Straße'] = record['Straße'];
  row.Ort = record.Ort;
  row.Status = record.Status;
  row.Zahlungsart = record.Zahlungsart;
  row.Eintrittsdatum = record.Eintrittsdatum;
  row.PLZ = record.PLZ;
  row.Geburtsdatum = record.Geburtsdatum;
  row.Geschlecht = record.Geschlecht;
  row['Mitglieds-Nr'] = record['Mitglieds-Nr'];
  row.Anrede = record.Anrede;
  row.Land = record.Land || 'Deutschland';
  row['Telefon_P1'] = record['Telefon_P1'];
  row['Mobil_P1'] = record['Mobil_P1'];
  row['E-Mail_P1'] = record['E-Mail_P1'];
  row.Titel = record.Titel;

  row.Kontoinhaber = record.Kontoinhaber;
  row.IBAN = record.IBAN;
  row.BIC = record.BIC;
  row.Kreditinstitut = record.Kreditinstitut;

  if (row.Zahlungsart === 'Lastschrift') {
    row['SEPA-Mandatstyp_1'] = record['SEPA-Mandatstyp_1'] || 'Folgelastschrift';
    row['SEPA-Merkmal_1'] = record['SEPA-Merkmal_1'] || 'wiederkehrend';
    row['SEPA-Unterschriftsdatum_1'] = record['SEPA-Unterschriftsdatum_1'];
    row['SEPA-Gültigkeitsdatum_1'] = record['SEPA-Gültigkeitsdatum_1'];
    row['SEPA-Benachrichtigungsdatum_1'] = record['SEPA-Benachrichtigungsdatum_1'];
  }

  row['Abteilung_1'] = 'Hauptverein';
  row['Abteilungseintritt_1'] = record.Eintrittsdatum;

  const uniqueSports = Array.from(new Set(record.Sportarten));
  for (let i = 0; i < Math.min(uniqueSports.length, 8); i++) {
    const idx = i + 2;
    row[`Abteilung_${idx}`] = uniqueSports[i];
    row[`Abteilungseintritt_${idx}`] = record.Eintrittsdatum;
  }

  const entry = parseDate(record.Eintrittsdatum);
  const year = entry.year;
  const startsAfterHalfYearCutoff = entry.month > 7 || (entry.month === 7 && entry.day >= 1);

  const annualType = record.Beitragsart;
  const halfType = contributionMap[annualType]?.half || null;

  if (startsAfterHalfYearCutoff && halfType) {
    row['Beitragsbezeichnung_1_1'] = halfType;
    row['Beitragsstart_1_1'] = record.Eintrittsdatum;
    row['Beitragsende_1_1'] = formatDate(31, 12, year);

    row['Beitragsbezeichnung_1_2'] = annualType;
    row['Beitragsstart_1_2'] = formatDate(1, 1, year + 1);
    row['Beitragsende_1_2'] = '';
  } else {
    row['Beitragsbezeichnung_1_1'] = annualType;
    row['Beitragsstart_1_1'] = record.Eintrittsdatum;
    row['Beitragsende_1_1'] = '';
  }

  return row;
}

const sourceItems = pickSourceItems(input);
if (!sourceItems.length) {
  throw new Error('Keine Eingabedaten gefunden. Erwartet: members/records/items/data oder ein Datensatz.');
}

const records = sourceItems.map((item) => normalizeRecord(item));
const rows = records.map((record, index) => buildRow(record, index));

const headerLine = csvColumns.map(csvEscape).join(';');
const dataLines = rows.map((row) => csvColumns.map((col) => csvEscape(row[col] || '')).join(';'));
const csvContent = ['\uFEFF' + headerLine, ...dataLines].join('\n');
const base64Data = Buffer.from(csvContent, 'utf8').toString('base64');

const fileName = typeof input.outputFileName === 'string' && input.outputFileName.trim()
  ? input.outputFileName.trim()
  : 'import.csv';

return [{
  json: {
    ok: true,
    records: rows.length,
    fileName
  },
  binary: {
    data: {
      data: base64Data,
      fileName,
      mimeType: 'text/csv; charset=utf-8'
    }
  }
}];
